-- ============================================================
-- MY MOOD — Aggiunta Google Maps URL per tutte le venue
-- ============================================================
-- Aggiunge la colonna google_maps_url e la popola automaticamente
-- ============================================================
-- Supabase → SQL Editor → incolla tutto → Run
-- ============================================================

-- Step 1: Aggiungi la colonna se non esiste
ALTER TABLE venues ADD COLUMN IF NOT EXISTS google_maps_url TEXT;

-- Step 2: Popola con Google Maps link per ogni venue
